import React from 'react';

const Account = () => {
  const handleLogout = () => {
    // Clear your user session (adjust key name if different)
    localStorage.removeItem('userId'); 
    window.location.href = '/login';
  };

  return (
    <div style={{ padding: '40px', maxWidth: '600px' }}>
      <h1 style={{ color: '#2d5a27', marginBottom: '20px' }}>Account Settings</h1>
      
      <div style={{ backgroundColor: 'white', padding: '25px', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h3 style={{ borderBottom: '1px solid #eee', paddingBottom: '10px' }}>Profile Information</h3>
        <p style={{ marginTop: '15px' }}><strong>Username:</strong> Admin_User</p>
        <p><strong>Email:</strong> admin@emetricx.com</p>
        <p><strong>Affiliation:</strong> National Mine Registry</p>
        
        <hr style={{ margin: '30px 0', border: 'none', borderTop: '1px solid #eee' }} />
        
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          <p style={{ color: '#666', fontSize: '0.9rem' }}>Moving the logout here as requested:</p>
          <button 
            onClick={handleLogout}
            style={{ 
              backgroundColor: '#d32f2f', 
              color: 'white', 
              border: 'none', 
              padding: '12px 24px', 
              borderRadius: '8px', 
              cursor: 'pointer',
              fontWeight: 'bold',
              width: 'fit-content'
            }}
          >
            Logout from Session
          </button>
        </div>
      </div>
    </div>
  );
};

export default Account;
